    setupRoutes() {
        // Main Dashboard
        this.app.get('/', (req, res) => {
            res.send(this.generateDashboardHTML());
        });

        // API Endpoints
        this.app.get('/api/status', (req, res) => {
            res.json({
                success: true,
                timestamp: this.lastUpdate,
                data: this.data
            });
        });

        this.app.get('/api/metrics', (req, res) => {
            res.json({
                success: true,
                metrics: this.data.performance
            });
        });

        this.app.get('/api/security', (req, res) => {
            res.json({
                success: true,
                security: this.data.security
            });
        });

        this.app.get('/api/automation', (req, res) => {
            res.json({
                success: true,
                automation: this.data.automation
            });
        });

        // Action Endpoints
        this.app.post('/api/actions/scan', (req, res) => {
            this.triggerSecurityScan();
            res.json({ success: true, message: 'Security scan initiated' });
        });

        this.app.post('/api/actions/backup', (req, res) => {
            this.triggerBackup();
            res.json({ success: true, message: 'Backup initiated' });
        });

        this.app.post('/api/actions/optimize', (req, res) => {
            this.triggerOptimization();
            res.json({ success: true, message: 'System optimization initiated' });
        });
    }

    startDataUpdates() {
        this.updateInterval = setInterval(() => {
            this.updateData();
        }, 30000); // Update every 30 seconds
    }

    updateData() {
        this.data = {
            system: this.getSystemHealth(),
            performance: this.getPerformanceMetrics(),
            security: this.getSecurityStatus(),
            automation: this.getAutomationStatus(),
            integrations: this.getIntegrationStatus()
        };
        this.lastUpdate = new Date();
    }

